import mysql.connector
import os

def import_data_with_load_infile(host, user, password, database, table_name, file_path, fields_terminated_by=',', lines_terminated_by='\n', enclosed_by='"', optionally_enclosed_by=False, ignore_lines=1):
    """
    Imports data from a CSV file into a MySQL table using LOAD DATA INFILE.

    Args:
        host (str): MySQL host.
        user (str): MySQL username.
        password (str): MySQL password.
        database (str): MySQL database name.
        table_name (str): The name of the table to import data into.
        file_path (str): The full path to the data file (e.g., CSV).
        fields_terminated_by (str): The character that separates fields. Default is ','.
        lines_terminated_by (str): The character that separates lines. Default is '\n'.
        enclosed_by (str): The character that encloses fields. Default is '"'.
        optionally_enclosed_by (bool): If True, uses OPTIONALLY ENCLOSED BY. Default is False.
        ignore_lines (int): Number of lines to ignore at the beginning of the file (e.g., header). Default is 1.
    """
    if not os.path.exists(file_path):
        print(f"Error: File not found at '{file_path}'")
        return

    conn = None
    cursor = None
    try:
        # Establish connection with local_infile=True
        conn = mysql.connector.connect(
            host=host,
            user=user,
            password=password,
            database=database,
            local_infile=True  # Enable LOCAL INFILE for the connection
        )
        cursor = conn.cursor()

        # Construct the LOAD DATA INFILE statement
        load_data_sql = f"LOAD DATA LOCAL INFILE '{file_path}' " \
                        f"INTO TABLE {table_name} " \
                        f"FIELDS TERMINATED BY '{fields_terminated_by}' "
        
        if optionally_enclosed_by:
            load_data_sql += f"OPTIONALLY ENCLOSED BY '{enclosed_by}' "
        else:
            load_data_sql += f"ENCLOSED BY '{enclosed_by}' "
        
        load_data_sql += f"LINES TERMINATED BY '{lines_terminated_by}' " \
                         f"IGNORE {ignore_lines} LINES"

        print(f"Executing: {load_data_sql}")
        cursor.execute(load_data_sql)
        conn.commit()
        print(f"Successfully imported data from '{file_path}' into table '{table_name}'.")
        print(f"Number of rows affected: {cursor.rowcount}")

    except mysql.connector.Error as err:
        print(f"Error importing data: {err}")
        if "The MySQL server is running with the --local-infile=0 option" in str(err):
            print("Please ensure 'local_infile=1' is set in your MySQL server configuration (my.cnf or my.ini) and the server is restarted.")
            print("Also, ensure 'local_infile=True' is passed to the mysql.connector.connect() call.")
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
    finally:
        if cursor:
            cursor.close()
        if conn:
            conn.close()

